interface TradingRecommendation {
  symbol: string
  action: 'LONG' | 'SHORT' | 'WAIT'
  confidence: number
  entryZone: { min: number; max: number }
  stopLoss: number
  takeProfits: number[]
  positionSize: number
  leverage: number
  riskAmount: number
  potentialReward: number
  reasoning: string[]
  indicators: {
    rsiSignal: string
    macdSignal: string
    bbSignal: string
    adxSignal: string
